#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,a,sum=0,minn=11,maxx=-1;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a;
        minn=min(minn,a);
        maxx=max(maxx,a);
        sum+=a;
    }
    sum-=(minn+maxx);
    printf("%.2lf",double(sum)/double(n-2));
    return 0;
}
